tlDataChunk*
tlParticleSystemFactoryChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::ParticleSystem::INSTANCING_INFO:
        dch = new tlParticleInstancingInfoChunk(&ch);
        break;
    case Pure3D::ParticleSystem::BASE_EMITTER_FACTORY:
        dch = new tlBaseEmitterFactoryChunk(&ch);
        break;
    case Pure3D::ParticleSystem::SPRITE_EMITTER_FACTORY:
        dch = new tlSpriteEmitterFactoryChunk(&ch);
        break;
    case Pure3D::ParticleSystem::DRAWABLE_EMITTER_FACTORY:
        dch = new tlDrawableEmitterFactoryChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

