int tlParticleSystemChunk::sortPriority = -1;

tlParticleSystemChunk::tlParticleSystemChunk()
{
    Init();
}

tlParticleSystemChunk::tlParticleSystemChunk(const tlParticleSystemChunk& ch)
{
    Init();
    *this = ch;
}

tlParticleSystemChunk::~tlParticleSystemChunk()
{

    if(name != NULL){
        strdelete(name);
    }
    if(factoryname != NULL){
        strdelete(factoryname);
    }
}

tlParticleSystemChunk::tlParticleSystemChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::ParticleSystem::SYSTEM);
    ident = Pure3D::ParticleSystem::SYSTEM;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    version = f->GetLong();
    f->GetPString(buf);
    name = strnew(buf);
    f->GetPString(buf);
    factoryname = strnew(buf);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::ParticleSystem::SYSTEM);
    }
}

void
tlParticleSystemChunk::Init()
{
    ident = Pure3D::ParticleSystem::SYSTEM;
    version = 0;
    name = NULL;
    factoryname = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::ParticleSystem::SYSTEM);
    }
}

long 
tlParticleSystemChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += strlen( name );
    s += strlen( factoryname );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlParticleSystemChunk&
tlParticleSystemChunk::operator=(const tlParticleSystemChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    name = strnew(a.name);
    factoryname = strnew(a.factoryname);

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlParticleSystemChunk::operator==(const tlDataChunk& a)
{

    const tlParticleSystemChunk* aptr = dynamic_cast<const tlParticleSystemChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(strcmp(factoryname, aptr->factoryname) != 0)
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlParticleSystemChunk::NameCompare(const tlDataChunk& a)
{

    const tlParticleSystemChunk* aptr = dynamic_cast<const tlParticleSystemChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


