{
    Init();
    *this = ch;
}

tlGeneratorAnimationChunk::~tlGeneratorAnimationChunk()
{

}

tlGeneratorAnimationChunk::tlGeneratorAnimationChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::ParticleSystem::GENERATOR_ANIMATION);
    ident = Pure3D::ParticleSystem::GENERATOR_ANIMATION;

    tlFile* f = ch->GetFile();

    version = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::ParticleSystem::GENERATOR_ANIMATION);
    }
}

void
tlGeneratorAnimationChunk::Init()
{
    ident = Pure3D::ParticleSystem::GENERATOR_ANIMATION;
    version = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::ParticleSystem::GENERATOR_ANIMATION);
    }
}

