tlBaseEmitterFactoryChunk::tlBaseEmitterFactoryChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::ParticleSystem::BASE_EMITTER_FACTORY);
    ident = Pure3D::ParticleSystem::BASE_EMITTER_FACTORY;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    version = f->GetLong();
    f->GetPString(buf);
    name = strnew(buf);
    particletype = f->GetLong();
    generatortype = f->GetLong();
    ztest = f->GetLong();
    zwrite = f->GetLong();
    fog = f->GetLong();
    maxparticles = f->GetLong();
    infinitelife = f->GetLong();
    rotationalcohesion = f->GetFloat();
    translationalcohesion = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::ParticleSystem::BASE_EMITTER_FACTORY);
    }
}

