tlDataChunk*
tlBaseEmitterFactoryChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::ParticleSystem::PARTICLE_ANIMATION:
        dch = new tlParticleAnimationChunk(&ch);
        break;
    case Pure3D::ParticleSystem::EMITTER_ANIMATION:
        dch = new tlEmitterAnimationChunk(&ch);
        break;
    case Pure3D::ParticleSystem::GENERATOR_ANIMATION:
        dch = new tlGeneratorAnimationChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

