tlSpriteEmitterFactoryChunk&
tlSpriteEmitterFactoryChunk::operator=(const tlSpriteEmitterFactoryChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    name = strnew(a.name);
    shadername = strnew(a.shadername);
    anglemode = a.anglemode;
    angle = a.angle;
    textureanimmode = a.textureanimmode;
    numtextureframes = a.numtextureframes;
    textureframerate = a.textureframerate;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlSpriteEmitterFactoryChunk::operator==(const tlDataChunk& a)
{

    const tlSpriteEmitterFactoryChunk* aptr = dynamic_cast<const tlSpriteEmitterFactoryChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(strcmp(shadername, aptr->shadername) != 0)
    {
        return false;
    }
    if(!(anglemode == aptr->anglemode))
    {
        return false;
    }
    if(!(angle == aptr->angle))
    {
        return false;
    }
    if(!(textureanimmode == aptr->textureanimmode))
    {
        return false;
    }
    if(!(numtextureframes == aptr->numtextureframes))
    {
        return false;
    }
    if(!(textureframerate == aptr->textureframerate))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

