bool 
tlSpriteEmitterFactoryChunk::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                version = tmp;
                return true;
            }
            return false;
        }
        case 1:
            strdelete(name);
            name = strnew(new_val);
            return true;
        case 2:
            strdelete(shadername);
            shadername = strnew(new_val);
            return true;
        case 3:
        {
            anglemode = (unsigned long) tlFourCC(new_val);
            return true;
        }
        case 4:
        {
            char* end_ptr;
            float tmp;
            tmp = (float)strtod(new_val, &end_ptr);
            if (*end_ptr == 0)
            {
                angle = tmp;
                return true;
            }
            return false;
        }
        case 5:
        {
            textureanimmode = (unsigned long) tlFourCC(new_val);
            return true;
        }
        case 6:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                numtextureframes = tmp;
                return true;
            }
            return false;
        }
        case 7:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                textureframerate = tmp;
                return true;
            }
            return false;
        }
        default:
            return false;
    }
}

