bool 
tlDrawableEmitterFactoryChunk::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                version = tmp;
                return true;
            }
            return false;
        }
        case 1:
            strdelete(name);
            name = strnew(new_val);
            return true;
        case 2:
            strdelete(drawablename);
            drawablename = strnew(new_val);
            return true;
        case 3:
        {
            anglemode = (unsigned long) tlFourCC(new_val);
            return true;
        }
        case 4:
        {
            char* end_ptr;
            float tmp;
            tmp = (float)strtod(new_val, &end_ptr);
            if (*end_ptr == 0)
            {
                angle = tmp;
                return true;
            }
            return false;
        }
        default:
            return false;
    }
}

bool 
tlDrawableEmitterFactoryChunk::SetFieldArrayValue(int fieldIndex, int arrayIndex, const char* new_val)
{
    return false;
}

tlDataChunk*
tlDrawableEmitterFactoryChunk::Copy()
{
    return new tlDrawableEmitterFactoryChunk(*this);
}

tlDataChunk*
tlDrawableEmitterFactoryChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::ParticleSystem::BASE_EMITTER_FACTORY:
        dch = new tlBaseEmitterFactoryChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

